import psycopg2
import time

class Database:
    def __init__(self):
        self.host = 'localhost'
        self.port = 5432

    def connect(self, timeout=5):
        # Connection establishment with retry logic
        start = time.time()
        while time.time() - start < timeout:
            try:
                conn = psycopg2.connect(
                    host=self.host,
                    port=self.port,
                    connect_timeout=1
                )
                return conn
            except psycopg2.OperationalError:
                time.sleep(0.5)
        raise ConnectionTimeout(f'Could not connect within {timeout}s')
